"""
Context Layer — 2 Chronicles chapters 35–36
Run: python3 scripts/zc-context-2chronicles-35-36.py

Key contextual notes:
- Ch 35: Josiah's great Passover (621 BCE) — the most detailed Passover account in Chronicles;
  Josiah's disguise at Megiddo (wayyithappēś echoing Ahab's disguise in 18:29);
  Jeremiah's lament at Megiddo (v25)
- Ch 36: Four kings in rapid succession (Jehoahaz, Jehoiakim, Jehoiachin, Zedekiah);
  progressive temple desecration; maʿal reaching its climax; lēʾên marpēʾ verdict;
  land's Sabbath rest (Lev 26:34); Cyrus decree closes the Hebrew canon
- v36:22 already present in file; omitted from dict (merge_comm skips existing keys)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRON2_CONTEXT_35_36 = {
  "35": {
    "1": "<p>Josiah&rsquo;s Passover is the narrative climax of his reform. The date — the fourteenth of the first month (Nisan 14) — is Passover&rsquo;s exact prescriptive date from Exod 12:6 and Num 9:3, the most precise calendrical observance in the Chronicler&rsquo;s account of any king. The Passover in 2 Kgs 23:21-23 is reported in three verses; Chronicles gives it an entire chapter, making it the crowning expression of Josiah&rsquo;s covenant faithfulness. The account emphasizes the role of Levites, the scale of sacrifice, and meticulous conformity to the Torah — all distinctively Chronicler concerns.</p>",
    "2": "<p>Josiah stations the priests in their divisions (<em>maḥlᵉqôtām</em>) and encourages them (<em>wayyᵉḥazzēq</em>) in the service of the temple. The verb <em>ḥāzaq</em> (strengthen, encourage) is a characteristic Chronicler word used when a king or leader properly supports the temple personnel (cf. Hezekiah in 29:34; 30:12). Josiah acts here as a Davidic organizer of worship, not merely an administrator — the king who catalyzes priestly function.</p>",
    "3": "<p>Josiah addresses the Levites specifically as those &ldquo;who taught all Israel&rdquo; (<em>hamᵉlammᵉdîm lᵉkol-yiśrāʾēl</em>) — a unique description emphasizing the Levites&rsquo; teaching function, which the Chronicler develops more than any other biblical author (cf. 17:7-9, Jehoshaphat&rsquo;s teaching Levites; Neh 8:7-9). The command to put the holy ark in the temple permanently signals a fundamental shift in Levitical function: the ark-bearing tribe, whose portage duty defined them since Sinai, is freed for instruction and temple service now that the ark has a permanent home. The Chronicler sees this as the fulfillment of David&rsquo;s organizational intent (1 Chr 23:26).</p>",
    "4": "<p>The preparation follows two written sources: the <em>miktāḇ</em> (writing) of David and the <em>miktāḇ</em> of Solomon — Josiah does not improvise the Passover organization but follows the precedents established by the two temple builders. This double appeal to textual authority reflects the Chronicler&rsquo;s concern with proper procedures being documented and transmitted. The reference to Solomon&rsquo;s organization connects this Passover to the temple&rsquo;s founding generation.</p>",
    "5": "<p>The Levites are stationed in the Holy Place (<em>baqqōḏeš</em>) according to family divisions, one Levitical division corresponding to each division of the lay people. The organization ensures that each lay worshiper has a Levitical mediator managing the sacrificial process. This elaborate logistical structure — matching Levitical divisions to lay divisions — is unique to Chronicles and reflects the Chronicler&rsquo;s vision of a perfectly organized covenant assembly.</p>",
    "6": "<p>The triple imperative to the Levites — slaughter, consecrate yourselves, prepare your brothers — reflects the liturgical precision Josiah demands. The phrase &ldquo;according to the word of the LORD through Moses&rdquo; (<em>kîdᵉḇar YHWH bᵉyad Mōšeh</em>) grounds the entire Passover in Mosaic authority. Every action is measured against Torah precedent, not royal innovation.</p>",
    "7": "<p>Josiah&rsquo;s personal contribution is enormous: 30,000 lambs and young goats + 3,000 bulls. The scale implies a Passover for a very large assembly — tens of thousands of worshipers. This surpasses even Hezekiah&rsquo;s Passover contribution (30:24) in precision, if not in scale. The Chronicler details the royal gift to underscore that this is a king who gives from his own resources for the people&rsquo;s worship — a model of covenant generosity contrasted with kings who plunder the temple.</p>",
    "8": "<p>Three named temple officials — Hilkiah (the high priest who found the Torah scroll in ch 34), Zechariah, and Jehiel — contribute 2,600 small animals and 300 oxen from their own resources. The voluntary character of these contributions (<em>nᵉḏāḇāh</em>, freewill offering) is significant: the leaders give willingly, not under compulsion. This mirrors the voluntary spirit of David&rsquo;s temple preparations (1 Chr 29:5-9), suggesting that Josiah&rsquo;s reform has succeeded in producing the same generous spirit.</p>",
    "9": "<p>Levitical leaders contribute an additional 5,000 small animals and 500 oxen. The Chronicler names six Levitical leaders (Conaniah, Shemaiah, Nethanel, Hashabiah, Jeiel, Jozabad) — their individuality matters to the Chronicler even in administrative lists. Total Passover contributions from king + officials + Levitical leaders: approximately 37,600 animals — a scale unparalleled in any other biblical Passover narrative.</p>",
    "10": "<p>The actual Passover service begins with everyone in position (<em>kᵉmišpāṭô</em>, according to his regulation/custom). The Levites stand in their divisions and the priests in their positions — the organizational groundwork laid in vv 3-9 is now executed flawlessly. The emphasis on proper positioning (<em>ʿāmad</em>, stood) reflects the Chronicler&rsquo;s valuation of ordered worship; spontaneous improvisation is never praised.</p>",
    "11": "<p>The Levites slaughter the Passover lambs while the priests sprinkle the blood — a division of labor that reflects the changed circumstances since Mosaic times. Originally, each family head slaughtered his own lamb (Exod 12:3-6); here the Levites serve as ritual agents for the lay people. The priests handle the blood (a priestly prerogative), while the Levites handle the slaughter and skinning. This represents the mature Chronicler&rsquo;s vision of differentiated but complementary priestly and Levitical function.</p>",
    "12": "<p>Burnt offerings are set aside (<em>wayyāsîrû</em>) from the Passover animals and distributed to lay family groupings to offer to YHWH as prescribed in &ldquo;the book of Moses&rdquo; — the direct Torah reference grounds even the distribution procedure in written authority. The Chronicler&rsquo;s Passover is thoroughly a Torah-compliance event; every procedural detail traces back to Mosaic legislation.</p>",
    "13": "<p>The Passover lambs are roasted with fire (<em>wayᵉbaššᵉlû ḇāʾēš</em>) as prescribed in Exod 12:8-9 (which explicitly prohibits boiling the Passover animal), while other holy offerings are boiled in pots, cauldrons, and pans. The Chronicler carefully distinguishes: fire-roasting for the Passover (Mosaic prescription), boiling for other sacrifices. This distinction maintains the distinctiveness of the Passover as a memorial meal with specific preparation requirements that separate it from ordinary sacrifice. The cooks then ran to distribute portions — suggesting enormous logistical pressure to serve the entire assembly.</p>",
    "14": "<p>The Levites prepare Passover portions for themselves and the priests because the priests (sons of Aaron) were occupied with the burnt offerings and fat portions all night. The Levites&rsquo; service to the priests — providing their Passover meal while Aaron&rsquo;s sons are still ministering — reverses the usual hierarchy temporarily and illustrates the Chronicler&rsquo;s esteem for the Levites as servants of the whole assembly, not merely subordinates of the priests.</p>",
    "15": "<p>The singers (sons of Asaph) remain at their assigned stations — they do not need to interrupt their musical ministry to prepare food. Jeduthun is identified as &ldquo;the king&rsquo;s seer&rdquo; (<em>ḥōzeh hammelek</em>), a title unique to Chronicles (cf. 1 Chr 25:5) that elevates the musical-prophetic function of the temple singers. The gatekeepers similarly remain at their stations — the entire temple personnel operates as an integrated system in which each person fulfills a specialized function without disruption. Verses 14-15 present the Passover as an event that perfectly activates the organizational structure that David and Solomon established.</p>",
    "16": "<p>The summary statement: all the service of YHWH was prepared that day — Passover + burnt offerings on the altar — according to the command of King Josiah. The phrase &ldquo;the command of King Josiah&rdquo; (<em>kᵉmiṣwat hammelek yōʾšîyāhû</em>) attributes the organizational achievement to royal initiative; Josiah&rsquo;s reform is not a priestly movement but a royal-prophetic movement led by the king. The Chronicler&rsquo;s ideal is a king who commands proper worship and whose command aligns perfectly with Torah requirements.</p>",
    "17": "<p>The Passover is followed immediately by the Feast of Unleavened Bread for seven days — the two feasts form a unified eight-day observance (Nisan 14 Passover + Nisan 15-21 Unleavened Bread). The phrase &ldquo;Israelites who were present&rdquo; (<em>bᵉnê yiśrāʾēl hannimṣāʾîm</em>) is significant: this includes northerners present in Jerusalem, paralleling Hezekiah&rsquo;s inclusive Passover in ch 30. Josiah&rsquo;s reform has reunified the covenant people around centralized worship.</p>",
    "18": "<p>The superlative evaluation: no Passover like this since the days of Samuel the prophet (<em>mîmê šᵉmûʾēl hannāḇîʾ</em>). The parallel in 2 Kgs 23:22 says &ldquo;since the days of the judges&rdquo; — Chronicles upgrades the comparison to Samuel specifically, who was both the last judge and the first major prophet to institute regular sanctuary worship (1 Sam 7:5-17). Samuel represents the ideal of prophetically-guided, Torah-centered worship; Josiah&rsquo;s Passover is the closest Israel has come to that ideal in the monarchic period. The emphasis that &ldquo;none of the kings of Israel had kept such a Passover&rdquo; indicts the entire northern monarchy; only Josiah among the kings achieves Samuel-era standards.</p>",
    "19": "<p>The dating — eighteenth year of Josiah&rsquo;s reign — synchronizes with the discovery of the Torah scroll (34:8) and the prophetess Huldah&rsquo;s oracle (34:22-28). The Passover in year 18 is the public, national expression of the personal covenant renewal Josiah undertook in response to hearing the Torah read. The reform has a precise historical location: Josiah began his religious reform at age 16 (34:3), intensified it at 26 when the scroll was found (34:8), and completed it at 27 with this Passover in year 18.</p>",
    "20": "<p>After the Passover, Neco king of Egypt comes up to fight at Carchemish on the Euphrates. This is the campaign of 609 BCE, when Neco was marching north to support the remnant of the Assyrian army against the rising Babylonian empire. Josiah goes out to intercept him. Historically, this may reflect Josiah&rsquo;s political alliance with Babylon (Judah&rsquo;s natural interest in Assyria&rsquo;s collapse) or perhaps an attempt to prevent Egyptian consolidation of the Levantine corridor. The abrupt contrast — from the Passover triumph to military catastrophe — structures the chapter to show that covenant faithfulness cannot shield against mortality.</p>",
    "21": "<p>Neco&rsquo;s message to Josiah is theologically explosive: &ldquo;God has commanded me to hurry&rdquo; (<em>mippî ʾĕlōhîm</em>, from the mouth of God). A pagan pharaoh claims divine authorization for his military campaign. The Chronicler presents this as a genuine divine word that Josiah refuses — &ldquo;he did not listen to the words of Neco from the mouth of God.&rdquo; The parallel with Ahab is unavoidable: Ahab refused to listen to Micaiah&rsquo;s true word (18:12-27) and died at Ramoth-gilead; Josiah refuses to listen to Neco&rsquo;s true word and dies at Megiddo. In both cases the righteous judgment comes not through an Israelite prophet but through an unexpected source.</p>",
    "22": "<p>Josiah disguises himself (<em>wayyithappēś</em>) to fight Neco — the identical word used for Ahab&rsquo;s disguise in 18:29. The verbal echo is unmistakable to any reader of Chronicles: the last great righteous king ends his life imitating the archetypal wicked king in the act that led to Ahab&rsquo;s death. Josiah&rsquo;s disguise is an act of defiance against the divine word through Neco — the most tragic irony in the Chronicler&rsquo;s history. He fights in the plain of Megiddo, the great battle plain of Israel&rsquo;s history (Judg 5:19; Zech 12:11).</p>",
    "23": "<p>The archers (<em>hayyōrîm</em>) hit King Josiah. His words — &ldquo;Take me away, for I am badly wounded (<em>heḥᵉlêtî mᵉʾōḏ</em>)&rdquo; — echo Ahab&rsquo;s identical situation (18:33, <em>heḥōlêtî</em>). Even the vocabulary of the mortal wound is shared. The coincidence of language reinforces the Chronicler&rsquo;s structural parallel: the greatest bad king (Ahab) and the greatest good king (Josiah) die the same death in the same act, defying a divine word they should have heeded.</p>",
    "24": "<p>Josiah is transferred from his battle chariot to his second chariot (<em>merkāḇat hamišneh</em>) and brought to Jerusalem to die. He is buried in the tombs of his fathers — a honorable burial, unlike Ahab (1 Kgs 22:38). &ldquo;All Judah and Jerusalem mourned for Josiah&rdquo; — the entire covenant community grieves. The mourning for Josiah is national, not just dynastic, because Josiah had made his reform a national project.</p>",
    "25": "<p>Jeremiah composed laments for Josiah (<em>wayyᵉqônēn yirmᵉyāhû ʿal-yōʾšîyāhû</em>). This is the only reference in the Hebrew Bible to Jeremiah composing laments for a specific person. The qînôt (laments) for Josiah were apparently collected into a written anthology — &ldquo;all the male and female singers commemorate Josiah in their laments; they made these a rule in Israel; behold, they are written in the laments.&rdquo; The &ldquo;laments&rdquo; (<em>haqqînôt</em>) is likely a separate collection, not the canonical Lamentations, whose heading attributes it to Jeremiah but whose content focuses on Jerusalem rather than Josiah. The mourning at Megiddo becomes proverbial: Zech 12:11 refers to &ldquo;the mourning of Hadad-rimmon in the plain of Megiddo&rdquo; as the measure of eschatological mourning.</p>",
    "26": "<p>Josiah&rsquo;s faithful deeds (<em>wᵉḥăsādāyw</em>) are characterized by the covenant-loyalty term <em>ḥesed</em> — the same word used for YHWH&rsquo;s steadfast love. Josiah&rsquo;s acts are measured against <em>kakkātûḇ bᵉtôrat YHWH</em> (as written in the law of YHWH), grounding his faithfulness in Torah conformity rather than royal achievement. The Chronicler evaluates kings by their relationship to the written Torah, and Josiah is the supreme example of a Torah-governed king.</p>",
    "27": "<p>The regnal summary concludes with the standard source citation: Book of the Kings of Israel and Judah. The Chronicler&rsquo;s history of Josiah thus ends not with a negative verdict but with a record of ḥăsādāyw — his loyal-love acts. Even though Josiah died by defying a divine word, the Chronicler evaluates his reign as a whole by its covenantal character. The death at Megiddo is a warning against presumption; it does not undo the faithfulness of Josiah&rsquo;s reign.</p>"
  },
  "36": {
    "1": "<p>&ldquo;The people of the land&rdquo; (<em>ʿam hāʾāreṣ</em>) — a specific sociological group in Chronicles designating the landed nobility or free citizenry of Judah, distinct from the royal household. They exercise popular sovereignty to choose Josiah&rsquo;s successor, bypassing formal succession. They select Jehoahaz rather than his older brother Eliakim (v4) — likely because Jehoahaz was seen as more resistant to Egyptian control. This popular assertion of sovereignty in the succession reflects the <em>ʿam hāʾāreṣ</em>&rsquo;s role in making (and sometimes breaking) kings in the final decades of Judah (cf. 2 Kgs 11:14-20; 21:24; 23:30).</p>",
    "2": "<p>Jehoahaz&rsquo;s three-month reign — the second shortest in the Davidic dynasty (Joash reigned three months in 2 Kgs 11, but as a child under Athaliah). The Chronicler gives no evaluation of Jehoahaz&rsquo;s character (contrast 2 Kgs 23:32: &ldquo;he did what was evil&rdquo;). Chronicles moves quickly through the last four kings because their reigns represent the working out of the accumulated sin narrated in the preceding chapters — each king merely confirms the trajectory already set.</p>",
    "3": "<p>Neco deposes Jehoahaz and imposes tribute: 100 talents of silver and one talent of gold. The imposition of tribute signals Judah&rsquo;s reduction to vassal status under Egypt. The Davidic king is now subject to foreign power — a reversal of the covenant promise that the nations would be tributary to David&rsquo;s heir. The precise tribute amounts echo the Chronicler&rsquo;s concern for historical specificity; these figures also appear in 2 Kgs 23:33.</p>",
    "4": "<p>Neco renames Eliakim as Jehoiakim — renaming a vassal king was a standard ancient Near Eastern practice asserting the suzerain&rsquo;s authority over the vassal&rsquo;s identity. Both names contain divine elements (Eliakim = &ldquo;God raises up&rdquo;; Jehoiakim = &ldquo;YHWH raises up&rdquo;), so the name change here is more about political submission than theological substitution. Jehoahaz is taken to Egypt and dies there — his fate fulfills Jeremiah&rsquo;s prophecy (Jer 22:11-12: &ldquo;he shall never return here&rdquo;).</p>",
    "5": "<p>Jehoiakim&rsquo;s 11-year reign (609-598 BCE). He is the king who burned Jeremiah&rsquo;s scroll (Jer 36:23) and who Jeremiah said would have the &ldquo;burial of a donkey&rdquo; (Jer 22:19). The Chronicler gives only the standard negative evaluation; Kings gives more detail (2 Kgs 23:35-24:5). Jehoiakim shifts allegiance between Egypt and Babylon multiple times during his reign as the geopolitical situation changes — he is a king whose policies are driven by calculation rather than covenant faithfulness.</p>",
    "6": "<p>Nebuchadnezzar comes and binds Jehoiakim in bronze chains (<em>baḥuštatayim</em>) to take him to Babylon. This is the first Babylonian intervention in Judah (605 BCE, after the Battle of Carchemish). The historicity of Jehoiakim actually being taken to Babylon is debated — 2 Kings says he died in Jerusalem. The Chronicler may be presenting a partial submission (Nebuchadnezzar came and subjugated him, possibly taking him briefly and releasing him as a vassal) or using the pattern of temple vessels removed to Babylon (v7) as the narrative framework regardless of what happened to the king personally.</p>",
    "7": "<p>Temple vessels (<em>mîkᵉlê bêt YHWH</em>) — great and small — begin their journey to Babylon. Nebuchadnezzar places them in his temple (<em>bêtô</em>) in Babylon. This is the Chronicler&rsquo;s central concern in ch 36: the progressive desecration and removal of the temple vessels is the narrative thread connecting all four kings. The vessels that Solomon had dedicated (chs 5-7) are systematically stripped; when the temple itself is finally burned (v19), nothing sacred remains. Dan 1:2 notes that vessels were placed in the treasury of Nebuchadnezzar&rsquo;s god — the reverse of temple dedication.</p>",
    "8": "<p>&ldquo;What was found against him&rdquo; (<em>hannimṣāʾ ʿālāyw</em>) — an enigmatic phrase, possibly referring to offenses documented in official records. The source citation points to the Book of the Kings of Israel and Judah. Jehoiakim is the only king for whom this specific phrase appears — it may indicate a judicial record of crimes brought against him, consistent with Jeremiah&rsquo;s extensive indictment of his reign (Jer 22-26; 36).</p>",
    "9": "<p>Jehoiachin&rsquo;s age is given as 8 in Chronicles versus 18 in 2 Kgs 24:8 — a well-known textual discrepancy; most textual critics treat the number 8 (<em>šᵉmōneh</em>) as a scribal error for 18 (<em>šᵉmōneh ʿeśrēh</em>). The three months and ten days is an oddly precise figure suggesting use of official records. Like his grandfather Josiah at age 8 (34:1), a very young king of Judah faces enormous political pressure — but Jehoiachin&rsquo;s reign ends in exile, not reform.</p>",
    "10": "<p>&ldquo;At the turn of the year&rdquo; (<em>lᵉtᵉšûḇat haššānāh</em>) — in spring (the agricultural/civil new year). Nebuchadnezzar sends for Jehoiachin (March-April 597 BCE) and takes him to Babylon along with more precious vessels. His uncle Mattaniah is renamed Zedekiah by Nebuchadnezzar — the second renaming by a foreign power in this chapter, again asserting vassalage through naming authority. Zedekiah is thus king not by popular choice (like Jehoahaz) but by Babylonian appointment — his legitimacy is entirely external.</p>",
    "11": "<p>Zedekiah&rsquo;s 11-year reign (597-586 BCE) — the longest of the four final kings. He is the last king of Judah to sit on David&rsquo;s throne in Jerusalem, making him the tragic terminus of the Davidic monarchy as an earthly institution. Chronicles abbreviates Zedekiah&rsquo;s reign drastically (compared to the extended treatment in Jer 27-44 and 2 Kgs 24:18-25:7), focusing entirely on the reasons for the exile rather than the events of the siege.</p>",
    "12": "<p>Zedekiah&rsquo;s defining failure: he did not humble himself (<em>lōʾ kānaʿ</em>) before Jeremiah the prophet. The verb <em>kānaʿ</em> (humble oneself) is the Chronicler&rsquo;s central diagnostic term for the covenant response that averts judgment: Rehoboam humbled himself and the catastrophe was limited (12:12); Manasseh humbled himself and was restored (33:12, 19, 23). Zedekiah&rsquo;s failure to humble himself before the prophet who spoke from YHWH&rsquo;s mouth is the decisive act that seals Jerusalem&rsquo;s fate. He also does not humble himself before Nebuchadnezzar (v13) — both political and prophetic submission are withheld.</p>",
    "13": "<p>Zedekiah&rsquo;s rebellion against Nebuchadnezzar — who had exacted an oath in God&rsquo;s name (<em>ʾᵃšer hišbîʿô bēʾlōhîm</em>) — is therefore also a breach of a covenant oath. The double hardening formula: <em>qāšāh ʿōrep</em> (stiffened his neck) + <em>ʾimmaṣ ʾet-lᵉḇāḇô</em> (hardened his heart) against turning to YHWH, the God of Israel. The Chronicler never says this of any previous king — the hardening of Pharaoh (Exod 4:21) uses identical vocabulary, casting Zedekiah&rsquo;s hardening as a Pharaoh-level resistance to divine word. The result, as with Pharaoh, is total catastrophe.</p>",
    "14": "<p>The indictment expands to encompass the entire leadership: the chief priests and the people also multiplied their <em>maʿal</em> (treachery/unfaithfulness). The key term <em>maʿal</em> — the Chronicler&rsquo;s diagnostic word for covenant betrayal that appears throughout the book (from Achan in Joshua to Saul in 1 Chr 10:13) — reaches its intensified form here: <em>hirḇû limaʿôl maʿal</em> (they greatly multiplied treachery). The priests following &ldquo;the abominations of the nations&rdquo; is the ultimate betrayal — those charged with guarding covenant boundaries have adopted the very practices that caused the Canaanites to lose the land (Lev 18:24-28).</p>",
    "15": "<p>YHWH&rsquo;s persistent sending of messengers — &ldquo;rising early and sending&rdquo; (<em>hašḵēm wᵉšālôaḥ</em>) — is the characteristic Jeremianic idiom for relentless prophetic warning (Jer 7:13, 25; 11:7; 25:3-4; 26:5; 29:19; 32:33; 35:14-15; 44:4). The Chronicler adopts this language to characterize YHWH&rsquo;s persistence: because he had compassion (<em>ḥāmal</em>) on his people and his dwelling place. The motivation is <em>ḥāmal</em> — the same verb used for a father&rsquo;s pity for his children. The exile is not YHWH&rsquo;s first response but his last, after long and compassionate warning.</p>",
    "16": "<p>The verdict on the final generation uses three verbs of prophetic rejection: mocking the messengers (<em>bᵉmaʿᵃlê malʾᵃḵê hāʾĕlōhîm</em> — mocking at them), despising his words (<em>ûmᵉbazzîm dᵉḇārāyw</em>), scoffing at his prophets (<em>ûmitôlᵉlîm bînᵉḇîʾāyw</em>). The wrath of YHWH rose (<em>wayyaʿal</em>) against his people until there was <em>lēʾên marpēʾ</em> (no remedy, no healing). <em>Marpēʾ</em> is the word for &ldquo;healing&rdquo; or &ldquo;remedy&rdquo; (from <em>rāpāʾ</em>); the prefix <em>lēʾên</em> negates it absolutely — there is no medicine left, no cure possible. This is the terminal diagnosis of a patient who refused every treatment. The Chronicler&rsquo;s most devastating verdict is medical, not merely judicial.</p>",
    "17": "<p>YHWH brings the king of the Chaldeans against them. The text specifies that Nebuchadnezzar killed the young men with the sword in the house of the sanctuary — not just in the city but in the temple precincts themselves. No compassion is shown for young men, women, or the elderly — the comprehensive formula of Deut 28:50 (&ldquo;a nation of fierce countenance that will show no regard for the elderly or favor to the young&rdquo;) is enacted. YHWH gave them all into his hand — the passive divine causation underlying the Babylonian agency is explicit: this is not random conquest but covenantally-authorized judgment.</p>",
    "18": "<p>The temple vessels — great and small, including the treasures of the temple and of the king and his officers — are all taken to Babylon. The comprehensive stripping of the temple is the inverse of Solomon&rsquo;s dedication: what was accumulated over centuries is removed in days. The vessels will eventually be returned under Cyrus (Ezra 1:7-11) — their restoration will be the first tangible sign of the exile&rsquo;s reversal. The Chronicler tracks the vessels as a proxy for the covenant: when they are in Jerusalem, YHWH dwells with his people; when they are in Babylon, the covenant bond is suspended.</p>",
    "19": "<p>The destruction triad: they burned the house of God, broke down the walls of Jerusalem, burned all its palaces, and destroyed all its precious objects. The temple — Solomon&rsquo;s temple, the subject of the Chronicler&rsquo;s narrative from 1 Chr 17 onward — is reduced to ash. The burning of <em>bêt hāʾĕlōhîm</em> is the Chronicler&rsquo;s most catastrophic event. The walls&rsquo; destruction strips Jerusalem of defensive identity; the palace fires erase the Davidic royal presence. The Hebrew phrase <em>wayyašḥîtû ʾet kol-kᵉlê maḥᵃmaddeyāh</em> (they destroyed all its precious objects) echoes Lamentations&rsquo; <em>maḥᵃmaddeyāh</em> — the precious things mourned in Lam 1:7, 10-11.</p>",
    "20": "<p>The survivors are taken into exile in Babylon as servants (<em>lᵃḇāḏîm</em>) — the word for slavery. From &ldquo;sons of Abraham&rdquo; and &ldquo;holy nation&rdquo; (Exod 19:6) to slaves in a foreign empire. &ldquo;Until the kingdom of Persia came to power&rdquo; — the mention of Persia here anticipates the resolution that will come through Cyrus in vv 22-23. The exile is named as temporary from the outset of the exile narrative: its terminus is already defined before the reader can despair.</p>",
    "21": "<p>The theological explanation of the exile: it fulfilled the word of YHWH through Jeremiah (Jer 25:11; 29:10 — seventy years for Babylon&rsquo;s dominance), &ldquo;until the land had paid off its Sabbaths&rdquo; (<em>ʿad-rāṣᵉtāh hāʾāreṣ ʾet-šabbᵉtōtêhā</em>). Leviticus 26:34-35 had warned that if Israel failed to observe the sabbatical years (every seventh year the land rests, Lev 25:1-7), the land would &ldquo;enjoy its Sabbaths while it lies desolate.&rdquo; The exile is understood as the land reclaiming its accumulated Sabbath rest that Israel had stolen from it by continuous cultivation. The Chronicler counts the exile not as punishment alone but as the land&rsquo;s restoration — YHWH enforces the Sabbath economics that Israel refused to implement voluntarily. The seventy years = approximately 490 years of violated sabbatical rest (70 × 7) since entering Canaan.</p>",
    "23": "<p>Cyrus&rsquo;s proclamation — the actual text of the decree as issued. &ldquo;YHWH the God of heaven has given me all the kingdoms of the earth, and he has charged me to build him a house in Jerusalem&rdquo; — a Persian king acknowledging Israel&rsquo;s God as the source of his empire is one of the most astonishing sentences in the Hebrew Bible. Isaiah had named Cyrus 150 years earlier (Isa 44:28; 45:1) and called him YHWH&rsquo;s <em>mᵉšîaḥ</em> (anointed). The final word of Chronicles — and of the Hebrew Bible in its canonical order — is <em>wᵉyaʿal</em>: &ldquo;let him go up.&rdquo; The Hebrew canon closes not with an ending but with an imperative of ascent. The exile that began with the descent to Babylon ends with the divine summons to go up to Jerusalem — the return anticipated by Isaiah (Isa 40:3-5, the highway from Babylon to Zion) and enacted by Ezra-Nehemiah. This is the canonical seam between Chronicles and Ezra, deliberately left open rather than closed.</p>"
  }
}

def main():
    existing = load_comm('mkt-context', '2chronicles')
    merge_comm(existing, CHRON2_CONTEXT_35_36)
    save_comm('mkt-context', '2chronicles', existing)
    print('2 Chronicles 35-36 context layer written.')

if __name__ == '__main__':
    main()
